import{_ as t,o as a,c as o,au as i}from"./chunks/framework.Bpqx6pAq.js";const f=JSON.parse('{"title":"Time-series utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/utilities/utils.time-series.md","filePath":"api/map/utilities/utils.time-series.md"}'),r={name:"api/map/utilities/utils.time-series.md"};function s(l,e,c,n,d,m){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="time-series-utilities" tabindex="-1">Time-series utilities <a class="header-anchor" href="#time-series-utilities" aria-label="Permalink to &quot;Time-series utilities&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This module provides functions for building and updating Chart.js-compatible time-series datasets from weather forecast or measurement data associated with probed locations and selected map features.</p><h2 id="constants" tabindex="-1">Constants <a class="header-anchor" href="#constants" aria-label="Permalink to &quot;Constants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td><code>ForecastProbeId</code></td><td>Fixed ID string (<code>&#39;forecast-probe&#39;</code>) used for forecast probe time-series entries.</td></tr></tbody></table><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="getchartoptions-title" tabindex="-1"><code>getChartOptions(title)</code> <a class="header-anchor" href="#getchartoptions-title" aria-label="Permalink to &quot;`getChartOptions(title)`&quot;">​</a></h3><p>Returns a base Chart.js options object with a titled chart, time-based x-axis, and a custom legend that uses point styles.</p><ul><li><strong>Parameters:</strong><ul><li><code>title</code> <em>(string)</em>: The chart title displayed at the top-left.</li></ul></li><li><strong>Returns:</strong> <code>Object</code> — A Chart.js options configuration object.</li></ul><hr><h3 id="getforecasttimeseries-feature-location-layer-starttime-endtime-runtime-forecastlayers-forecastmodel-forecastlevel-forecastlevelunit-weacastapi-fetchdelay" tabindex="-1"><code>getForecastTimeSeries({ feature, location, layer, startTime, endTime, runTime, forecastLayers, forecastModel, forecastLevel, forecastLevelUnit, weacastApi, fetchDelay })</code> <a class="header-anchor" href="#getforecasttimeseries-feature-location-layer-starttime-endtime-runtime-forecastlayers-forecastmodel-forecastlevel-forecastlevelunit-weacastapi-fetchdelay" aria-label="Permalink to &quot;`getForecastTimeSeries({ feature, location, layer, startTime, endTime, runTime, forecastLayers, forecastModel, forecastLevel, forecastLevelUnit, weacastApi, fetchDelay })`&quot;">​</a></h3><p>Builds an array of time-series descriptors for weather forecast variables at a probed location or feature.</p><ul><li><strong>Parameters:</strong><ul><li><code>feature</code> <em>(Object | null)</em>: The clicked GeoJSON feature, or <code>null</code> for a position-only probe.</li><li><code>location</code> <em>(Object)</em>: The probe location <code>{ lng, lat }</code>.</li><li><code>layer</code> <em>(Object)</em>: The layer associated with the feature.</li><li><code>startTime</code> <em>(Moment, optional)</em>: Start of the time range. Defaults to current range start.</li><li><code>endTime</code> <em>(Moment, optional)</em>: End of the time range. Defaults to current range end.</li><li><code>runTime</code> <em>(Moment, optional)</em>: Specific forecast run time to filter values by.</li><li><code>forecastLayers</code> <em>(Array)</em>: Layers tagged as weather/forecast from which variables are collected.</li><li><code>forecastModel</code> <em>(Object)</em>: The active forecast model definition.</li><li><code>forecastLevel</code> <em>(number | null)</em>: Optional vertical level.</li><li><code>forecastLevelUnit</code> <em>(string)</em>: Unit label for the level.</li><li><code>weacastApi</code> <em>(Object)</em>: The Weacast API client instance.</li><li><code>fetchDelay</code> <em>(number, optional)</em>: Debounce delay in milliseconds for data re-fetches. Defaults to <code>250</code>.</li></ul></li><li><strong>Returns:</strong> <code>Array</code> — An array of series descriptor objects, each with <code>probedLocationData</code>, <code>data</code> (Promise), <code>variable</code> (name, label, unit, chartjs options), and a <code>fetch()</code> method for data refresh.</li></ul><hr><h3 id="getmeasuretimeseries-feature-location-layer-layers-starttime-endtime-runtime-level-levelunit-probefunction-fetchdelay" tabindex="-1"><code>getMeasureTimeSeries({ feature, location, layer, layers, startTime, endTime, runTime, level, levelUnit, probeFunction, fetchDelay })</code> <a class="header-anchor" href="#getmeasuretimeseries-feature-location-layer-layers-starttime-endtime-runtime-level-levelunit-probefunction-fetchdelay" aria-label="Permalink to &quot;`getMeasureTimeSeries({ feature, location, layer, layers, startTime, endTime, runTime, level, levelUnit, probeFunction, fetchDelay })`&quot;">​</a></h3><p>Builds an array of time-series descriptors for measurement variables at a probed location or feature.</p><ul><li><strong>Parameters:</strong><ul><li><code>feature</code> <em>(Object | null)</em>: The clicked GeoJSON feature, or <code>null</code> for a position-only probe.</li><li><code>location</code> <em>(Object)</em>: The probe location <code>{ lng, lat }</code>.</li><li><code>layer</code> <em>(Object)</em>: The primary layer associated with the feature.</li><li><code>layers</code> <em>(Array, optional)</em>: Additional layers whose variables should be included.</li><li><code>startTime</code> <em>(Moment, optional)</em>: Start of the time range.</li><li><code>endTime</code> <em>(Moment, optional)</em>: End of the time range.</li><li><code>level</code> <em>(number | null)</em>: Optional vertical level.</li><li><code>levelUnit</code> <em>(string)</em>: Unit label for the level.</li><li><code>probeFunction</code> <em>(Function, optional)</em>: Custom async probe function <code>({ feature, location, layer, level, startTime, endTime }) =&gt; data</code>. When provided, replaces the default <code>getMeasureForFeature</code> call.</li><li><code>fetchDelay</code> <em>(number, optional)</em>: Debounce delay in milliseconds for data re-fetches. Defaults to <code>250</code>.</li></ul></li><li><strong>Returns:</strong> <code>Array</code> — An array of series descriptor objects (same shape as <code>getForecastTimeSeries</code>).</li></ul><hr><h3 id="updatetimeseries-previoustimeseries" tabindex="-1"><code>updateTimeSeries(previousTimeSeries)</code> <a class="header-anchor" href="#updatetimeseries-previoustimeseries" aria-label="Permalink to &quot;`updateTimeSeries(previousTimeSeries)`&quot;">​</a></h3><p>Recomputes the full set of time-series for the current activity state: probed location and/or selected features. Handles both measure and forecast probes, supports grouping by variable or by feature, and restores <code>visible</code>, <code>pinned</code>, and <code>logarithmic</code> state from a previous series array.</p><ul><li><strong>Parameters:</strong><ul><li><code>previousTimeSeries</code> <em>(Array | null)</em>: The previous time-series array, used to restore UI state. Pass <code>null</code> on first call.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Array&gt;</code> — The new time-series array. Each entry has <code>{ id, label, series[] }</code>. The first visible series is automatically set to <code>visible: true</code> if none are visible. Measure time-series are preferred over forecast probes when both are available.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Time-series can be grouped by variable instead of by feature by setting <code>Store.patch(&#39;timeseries.groupBy&#39;, &#39;variable&#39;)</code>. In variable grouping mode, datasets are coloured using a 10-colour <code>Set1</code> Chroma.js scale.</p></div>',22)])])}const h=t(r,[["render",s]]);export{f as __pageData,h as default};
